import{_ as o,o as u,c as q,a0 as a}from"./chunks/framework.CSK6mTG2.js";const d=JSON.parse('{"title":"幻觉问题：大模型为什么\\"胡说八道\\"","description":"","frontmatter":{"title":"幻觉问题：大模型为什么\\"胡说八道\\"","author":"唐超","date":"2026-07-18T00:00:00.000Z"},"headers":[],"relativePath":"menuAI/hallucination-problem.md","filePath":"menuAI/hallucination-problem.md"}'),r={name:"menuAI/hallucination-problem.md"};function e(p,t,n,l,i,h){return u(),q("div",null,[...t[0]||(t[0]=[a('<h1 id="幻觉问题-大模型为什么-胡说八道" tabindex="-1">幻觉问题：大模型为什么&quot;胡说八道&quot; <a class="header-anchor" href="#幻觉问题-大模型为什么-胡说八道" aria-label="Permalink to &quot;幻觉问题：大模型为什么&quot;胡说八道&quot;&quot;">​</a></h1><p>你问 ChatGPT：&quot;林黛玉倒拔垂杨柳是在哪一回？&quot;</p><p>它一本正经地回答：&quot;在《红楼梦》第七回，林黛玉因不满薛宝钗送来的宫花，一怒之下在贾府后院倒拔垂杨柳，震惊了在场所有人……&quot;</p><p>但凡读过《红楼梦》的人都知道这是胡扯——林黛玉是书香门第的小姐，倒拔垂杨柳那是鲁智深干的事。但模型说得有鼻子有眼，连回目都编出来了。</p><p>这就是大模型最让人头疼的毛病——<strong>幻觉（Hallucination）</strong>。</p><p>说白了，就是大模型&quot;一本正经地胡说八道&quot;。它不是在撒谎，它真的&quot;相信&quot;自己说的是对的——这正是幻觉最可怕的地方。</p><p>今天我们就来扒一扒：幻觉到底是怎么产生的，能不能治，以及为什么短期内不可能完全消灭。</p><hr><h2 id="一、先搞清楚-幻觉不是-犯错-是-自信地编" tabindex="-1">一、先搞清楚：幻觉不是&quot;犯错&quot;，是&quot;自信地编&quot; <a class="header-anchor" href="#一、先搞清楚-幻觉不是-犯错-是-自信地编" aria-label="Permalink to &quot;一、先搞清楚：幻觉不是&quot;犯错&quot;，是&quot;自信地编&quot;&quot;">​</a></h2><p>普通的&quot;答错&quot;和&quot;幻觉&quot;有本质区别。</p><p>打个比方：你问一个学生&quot;巴黎的首都是哪？&quot;他犹豫一下说&quot;好像是里昂？&quot;——这是答错，他自己也不确定。</p><p>但幻觉是这样的：你问他&quot;李白写过《静夜思》吗？&quot;他斩钉截铁地说&quot;写过，而且还在诗里提到了量子力学&quot;——他不仅答错了，还特别自信，还编了一堆细节。</p><p><strong>幻觉的三个特征</strong>：</p><ol><li><strong>流畅性</strong>——输出看起来完全正常，语法、逻辑、语气都挑不出毛病。</li><li><strong>虚假性</strong>——内容是错的，或者根本不存在。</li><li><strong>自信性</strong>——模型没有任何&quot;不确定&quot;的信号，该编就编。</li></ol><p>这就是为什么幻觉比&quot;直接答错&quot;更危险——你很难一眼看出来它在胡说。一个胡言乱语的模型没人会上当，但一个&quot;看起来很专业&quot;的模型却可能误导千万人。</p><hr><h2 id="二、幻觉的根源-训练机制的-先天缺陷" tabindex="-1">二、幻觉的根源：训练机制的&quot;先天缺陷&quot; <a class="header-anchor" href="#二、幻觉的根源-训练机制的-先天缺陷" aria-label="Permalink to &quot;二、幻觉的根源：训练机制的&quot;先天缺陷&quot;&quot;">​</a></h2><p>要理解幻觉为什么会产生，得回到大模型的工作原理。</p><h3 id="_2-1-大模型本质是-概率接龙" tabindex="-1">2.1 大模型本质是&quot;概率接龙&quot; <a class="header-anchor" href="#_2-1-大模型本质是-概率接龙" aria-label="Permalink to &quot;2.1 大模型本质是&quot;概率接龙&quot;&quot;">​</a></h3><p>你还记得我们讲过自回归生成吗？大模型的核心能力就是——<strong>根据前面的词，预测下一个最可能出现的词</strong>。</p><p>它不&quot;知道&quot;任何事实，它只是在算概率。&quot;巴黎是法国首都&quot;之所以能答对，是因为训练语料里&quot;巴黎&quot;和&quot;法国首都&quot;一起出现的概率特别高。</p><p>但问题是：<strong>概率高 ≠ 事实正确</strong>。</p><p>打个比方：你读了一万本武侠小说，里面&quot;高手&quot;和&quot;飞檐走壁&quot;经常一起出现。于是你形成了一个印象——高手都能飞。但这只是统计规律，不是物理事实。大模型也一样，它学到的是&quot;语言的统计规律&quot;，而不是&quot;世界的真实规律&quot;。</p><p>当训练语料里某个事实出现得少、或者跟其他词的关联更强时，模型就可能&quot;算错概率&quot;，给出一个听起来合理但完全编造的答案。</p><h3 id="_2-2-知识-和-表达-混在了一起" tabindex="-1">2.2 &quot;知识&quot;和&quot;表达&quot;混在了一起 <a class="header-anchor" href="#_2-2-知识-和-表达-混在了一起" aria-label="Permalink to &quot;2.2 &quot;知识&quot;和&quot;表达&quot;混在了一起&quot;">​</a></h3><p>大模型还有一个结构性问题：<strong>它把&quot;事实知识&quot;和&quot;语言能力&quot;存在同一套参数里</strong>。</p><p>打个比方：你有一个柜子，里面同时放着课本、小说、地摊文学、八卦杂志。你需要回答&quot;地球到月亮多远&quot;时，得从这一堆书里翻——但柜子不分类，你可能翻到课本说是 38 万公里，也可能翻到八卦杂志说&quot;月亮是外星人基地&quot;。</p><p>大模型就是这样。它的参数里既有维基百科的严谨知识，也有网络小说的虚构情节，还有论坛里的以讹传讹。生成时哪个&quot;概率高&quot;就输出哪个，根本分不清哪些是&quot;知识&quot;、哪些是&quot;故事&quot;。</p><h3 id="_2-3-没有-不知道-这个选项" tabindex="-1">2.3 没有&quot;不知道&quot;这个选项 <a class="header-anchor" href="#_2-3-没有-不知道-这个选项" aria-label="Permalink to &quot;2.3 没有&quot;不知道&quot;这个选项&quot;">​</a></h3><p>这是最要命的一点。</p><p>人类被问到不会的问题，会说&quot;我不知道&quot;。但大模型的训练方式是<strong>总是要给出一个答案</strong>——它被训练成&quot;接龙机器&quot;，永远在预测下一个词，从来不会被允许说&quot;停&quot;。</p><p>打个比方：你逼着一个没复习的学生闭卷考试，而且规定&quot;不准交白卷&quot;。他不会的题怎么办？只能编。编得越像回事，越可能蒙混过关。</p><p>大模型也是被&quot;逼&quot;着回答的。训练数据里&quot;我不知道&quot;这种回答太少，模型没学会&quot;承认无知&quot;这件事。所以它宁可编一个，也不会说&quot;我不懂&quot;。</p><hr><h2 id="三、三类幻觉-不是所有-胡说-都一样" tabindex="-1">三、三类幻觉：不是所有&quot;胡说&quot;都一样 <a class="header-anchor" href="#三、三类幻觉-不是所有-胡说-都一样" aria-label="Permalink to &quot;三、三类幻觉：不是所有&quot;胡说&quot;都一样&quot;">​</a></h2><p>业界把幻觉分成三类，治疗思路也不一样。</p><h3 id="_3-1-事实性幻觉-编造不存在的事实" tabindex="-1">3.1 事实性幻觉：编造不存在的事实 <a class="header-anchor" href="#_3-1-事实性幻觉-编造不存在的事实" aria-label="Permalink to &quot;3.1 事实性幻觉：编造不存在的事实&quot;">​</a></h3><p>最常见的一类。模型说&quot;爱因斯坦 1921 年获得诺贝尔化学奖&quot;——其实他得的是物理学奖。或者说&quot;苏轼写过《水调歌头·明月几时有》和《相对论》&quot;——后一个是编的。</p><p>这类幻觉的特征是：<strong>涉及具体的人、事、时间、数字，可以客观验证</strong>。模型把张冠李戴、时间错位、无中生有。</p><p>治疗这类幻觉最有效的是 <strong>RAG（检索增强生成）</strong>——后面会讲。</p><h3 id="_3-2-逻辑性幻觉-推理过程出错" tabindex="-1">3.2 逻辑性幻觉：推理过程出错 <a class="header-anchor" href="#_3-2-逻辑性幻觉-推理过程出错" aria-label="Permalink to &quot;3.2 逻辑性幻觉：推理过程出错&quot;">​</a></h3><p>这类更隐蔽。模型可能引用的事实都对，但推理链条断了。</p><p>比如：&quot;所有的猫都是哺乳动物，所有的哺乳动物都下蛋，所以猫下蛋。&quot;——前半句对，后半句错，结论错。但模型一路&quot;接龙&quot;下来，每一步都&quot;看起来&quot;合理。</p><p>这类幻觉最难治，因为它不是&quot;知识&quot;的问题，而是&quot;推理能力&quot;的问题。这也是为什么推理模型（如 o1、DeepSeek-R1）会强调&quot;思维链显性化&quot;——让模型把推理过程写出来，方便检查哪一步错了。</p><h3 id="_3-3-一致性幻觉-前后说法打架" tabindex="-1">3.3 一致性幻觉：前后说法打架 <a class="header-anchor" href="#_3-3-一致性幻觉-前后说法打架" aria-label="Permalink to &quot;3.3 一致性幻觉：前后说法打架&quot;">​</a></h3><p>同一轮对话里，模型先说&quot;地球是圆的&quot;，过几轮又说&quot;地球其实是平的&quot;。自相矛盾。</p><p>这类幻觉通常出现在长对话里——模型&quot;忘了&quot;自己前面说过什么。根因是上下文窗口有限，或者注意力衰减，早期对话的权重被稀释了。</p><p>打个比方：一个人讲故事讲了两小时，前面说主角是孤儿，后面突然冒出个亲妈来——他自己都记不清前面编了什么。</p><hr><h2 id="四、怎么治-缓解幻觉的四大手段" tabindex="-1">四、怎么治？缓解幻觉的四大手段 <a class="header-anchor" href="#四、怎么治-缓解幻觉的四大手段" aria-label="Permalink to &quot;四、怎么治？缓解幻觉的四大手段&quot;">​</a></h2><p>幻觉治不绝，但可以缓解。业界目前有四条路线。</p><h3 id="_4-1-rag-开卷考试-别闭卷瞎编" tabindex="-1">4.1 RAG：开卷考试，别闭卷瞎编 <a class="header-anchor" href="#_4-1-rag-开卷考试-别闭卷瞎编" aria-label="Permalink to &quot;4.1 RAG：开卷考试，别闭卷瞎编&quot;">​</a></h3><p><strong>RAG（检索增强生成）</strong> 是目前公认最有效的手段。</p><p>思路特别直接：既然模型会编，那就别让它&quot;闭卷考试&quot;——<strong>先查资料，再回答</strong>。</p><p>打个比方：你问一个学生&quot;2024 年诺贝尔文学奖得主是谁？&quot;闭卷他可能瞎编一个，但如果你允许他查 Google，他查到了再告诉你，那就靠谱多了。</p><p>RAG 的流程是：用户提问 → 从知识库（向量数据库）检索相关文档 → 把文档和问题一起喂给模型 → 模型基于文档生成答案。这样模型就不是&quot;凭记忆&quot;回答，而是&quot;看着资料&quot;回答。</p><p>RAG 大幅降低了事实性幻觉，但也有局限：检索质量不高时，模型可能基于错误的资料继续胡说；而且模型可能&quot;无视&quot;检索到的资料，继续按自己的记忆编——这叫&quot;检索不忠实&quot;。</p><h3 id="_4-2-解码约束-别让模型-放飞" tabindex="-1">4.2 解码约束：别让模型&quot;放飞&quot; <a class="header-anchor" href="#_4-2-解码约束-别让模型-放飞" aria-label="Permalink to &quot;4.2 解码约束：别让模型&quot;放飞&quot;&quot;">​</a></h3><p>第二个思路是<strong>从生成阶段下手</strong>，限制模型的&quot;创作自由&quot;。</p><p>大模型生成时，每一步都在选下一个词。如果完全不限制，模型可能选那些&quot;听起来顺&quot;但&quot;不对&quot;的词。解码约束就是给这个选择过程加规则。</p><p>比如<strong>降低温度（temperature）</strong>——温度越低，模型越倾向于选概率最高的词，输出越&quot;保守&quot;。温度高时模型敢&quot;飞&quot;，温度低时它就&quot;稳&quot;。</p><p>再比如<strong>约束解码（Constrained Decoding）</strong>——限定模型只能从某个词表里选词，或者必须符合某种格式（如 JSON Schema）。这样能防止模型&quot;跑题&quot;。</p><p>打个比方：温度调节就像给一个话痨装个&quot;音量旋钮&quot;——不是不让他说话，而是让他说话&quot;稳&quot;一点。约束解码则是给他一份&quot;发言提纲&quot;——别瞎扯，按提纲来。</p><h3 id="_4-3-自洽校验-让模型-自己检查自己" tabindex="-1">4.3 自洽校验：让模型&quot;自己检查自己&quot; <a class="header-anchor" href="#_4-3-自洽校验-让模型-自己检查自己" aria-label="Permalink to &quot;4.3 自洽校验：让模型&quot;自己检查自己&quot;&quot;">​</a></h3><p>这个思路很有意思：<strong>让模型生成多个答案，看它们一不一致</strong>。</p><p>如果模型每次回答都不一样，说明它&quot;心里没底&quot;——大概率在编。如果多次回答都一致，可信度就高一些。</p><p>更进阶的做法是<strong>让模型扮演&quot;审查员&quot;</strong>：先让它生成一个答案，再提示它&quot;请检查上面的回答有没有事实错误&quot;，让它自己挑毛病。这叫&quot;自我反思&quot;（Self-Reflection）或&quot;自我一致性&quot;（Self-Consistency）。</p><p>打个比方：你让一个学生先写答案，再让他当老师批改自己的卷子。虽然不一定能挑出所有错，但至少能发现一部分明显的问题。</p><p>这个方法效果不错，但成本高——生成次数翻倍甚至更多，算力和时间都上去了。</p><h3 id="_4-4-数据质量-从源头治" tabindex="-1">4.4 数据质量：从源头治 <a class="header-anchor" href="#_4-4-数据质量-从源头治" aria-label="Permalink to &quot;4.4 数据质量：从源头治&quot;">​</a></h3><p>最后一个，也是治本的——<strong>把训练数据弄干净</strong>。</p><p>前面说过，大模型的参数里混着&quot;知识&quot;和&quot;噪音&quot;。如果训练数据本身就有大量错误信息（地摊文学、虚假新闻、论坛谣言），模型学到的&quot;知识&quot;自然就不可靠。</p><p>所以预训练阶段的数据清洗越来越被重视：去重、过滤低质量内容、平衡数据来源、剔除明显的事实错误。SFT 阶段更要保证标注答案的准确性——一个错误的标准答案，会让模型&quot;理直气壮&quot;地学到错误。</p><p>打个比方：你想培养一个博学的学生，首先得给他读靠谱的书。如果从小就给他看地摊文学，长大了他当然满嘴跑火车。</p><p>数据质量是&quot;地基&quot;，地基不牢，上面再多的技巧都是治标不治本。</p><hr><h2 id="五、为什么幻觉短期内治不绝" tabindex="-1">五、为什么幻觉短期内治不绝？ <a class="header-anchor" href="#五、为什么幻觉短期内治不绝" aria-label="Permalink to &quot;五、为什么幻觉短期内治不绝？&quot;">​</a></h2><p>讲了这么多手段，但得说句实话：<strong>幻觉在可见的未来不可能完全消除</strong>。</p><p>原因有三：</p><p><strong>第一，概率模型的本质决定的</strong>。大模型是基于概率的&quot;接龙机器&quot;，它没有&quot;真伪判断&quot;的能力。你可以缓解，但没法让它从底层变成一个&quot;只说真话&quot;的系统——除非换一种完全不同的架构。</p><p><strong>第二，&quot;不知道&quot;很难定义</strong>。什么时候该说&quot;不知道&quot;？这本身就是一个判断题。模型说得太保守，用户觉得它没用；说得太自信，又容易幻觉。这个&quot;度&quot;很难拿捏。</p><p><strong>第三，世界在变</strong>。模型训练时有截止时间，之后发生的新事它根本不知道。你问它&quot;2026 年某月某日发生了什么&quot;，它要么说不知道，要么编——没有中间选项。而知识更新（持续学习）本身又会带来新问题（灾难性遗忘）。</p><p>所以业界对幻觉的态度正在从&quot;消灭它&quot;转向&quot;管理它&quot;——通过 RAG、校验、人机协作等手段，把幻觉控制在&quot;可接受&quot;的范围内，而不是追求&quot;零幻觉&quot;。</p><hr><h2 id="六、给开发者的几句实在话" tabindex="-1">六、给开发者的几句实在话 <a class="header-anchor" href="#六、给开发者的几句实在话" aria-label="Permalink to &quot;六、给开发者的几句实在话&quot;">​</a></h2><p>如果你在做大模型应用，面对幻觉，几条实操建议：</p><ol><li><p><strong>能上 RAG 就上 RAG</strong>。涉及具体事实、数据、文档的场景，RAG 是性价比最高的方案。别指望模型&quot;凭记忆&quot;答对。</p></li><li><p><strong>关键场景加校验</strong>。生成代码、医疗建议、法律文书这种容错率低的场景，一定要加二次校验——要么人工 review，要么让另一个模型检查。</p></li><li><p><strong>温度别设太高</strong>。需要事实性回答的场景，温度设 0 到 0.3；需要创意的场景再往上调。高温 + 事实问答 = 灾难。</p></li><li><p><strong>提示词里加约束</strong>。比如&quot;如果不确定，请回答&#39;我不知道&#39;&quot;——虽然不一定管用，但能减少一部分编造。</p></li><li><p><strong>给模型&quot;退路&quot;</strong>。在系统提示里明确：&quot;你是一个严谨的助手，对于不确定的问题，请直接说&#39;我不确定&#39;，不要编造。&quot;这在很多场景下能显著降低幻觉率。</p></li></ol><hr><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>幻觉类型</th><th>根源</th><th>主要缓解手段</th></tr></thead><tbody><tr><td>事实性</td><td>知识与噪音混杂</td><td>RAG、数据清洗</td></tr><tr><td>逻辑性</td><td>推理链条断裂</td><td>思维链显性化、自洽校验</td></tr><tr><td>一致性</td><td>上下文遗忘</td><td>长上下文优化、记忆机制</td></tr></tbody></table><p>幻觉是大模型&quot;与生俱来&quot;的毛病，根源在于它的概率本质和训练方式。我们没法消灭它，但可以通过 RAG、解码约束、自洽校验、数据清洗等手段把它&quot;管&quot;住。</p><p>理解了幻觉的根源，你在做大模型应用时就不会&quot;盲目信任&quot;模型——你会知道什么时候该加 RAG，什么时候该加校验，什么时候该让模型说&quot;我不知道&quot;。</p><p>毕竟，一个知道自己&quot;会犯错&quot;的系统，比一个永远&quot;自信满满&quot;的系统，要靠谱得多。</p>',93)])])}const g=o(r,[["render",e]]);export{d as __pageData,g as default};
